import type { ResolvedPlacement, PositionOptions, PositionResult } from './types';

interface Rect {
  x: number;
  y: number;
  width: number;
  height: number;
}

const AUTO_ORDER: ResolvedPlacement[] = [
  'bottom-start',
  'bottom-center',
  'top-start',
  'top-center',
  'right-start',
  'right-center',
  'left-start',
  'left-center',
  'bottom-end',
  'top-end',
  'right-end',
  'left-end',
];

const OPPOSITE: Record<ResolvedPlacement, ResolvedPlacement> = {
  'bottom-start': 'top-start',
  'bottom-center': 'top-center',
  'bottom-end': 'top-end',
  'top-start': 'bottom-start',
  'top-center': 'bottom-center',
  'top-end': 'bottom-end',
  'right-start': 'left-start',
  'right-center': 'left-center',
  'right-end': 'left-end',
  'left-start': 'right-start',
  'left-center': 'right-center',
  'left-end': 'right-end',
};

// Fallback placements tried after the opposite fails. Provides cross-axis
// alternatives so e.g. a bottom tooltip that can't flip to top tries right/left.
const ADJACENT: Record<ResolvedPlacement, ResolvedPlacement[]> = {
  'bottom-start': ['right-start', 'left-start'],
  'bottom-center': ['right-center', 'left-center'],
  'bottom-end': ['right-end', 'left-end'],
  'top-start': ['right-start', 'left-start'],
  'top-center': ['right-center', 'left-center'],
  'top-end': ['right-end', 'left-end'],
  'right-start': ['bottom-start', 'top-start'],
  'right-center': ['bottom-center', 'top-center'],
  'right-end': ['bottom-end', 'top-end'],
  'left-start': ['bottom-start', 'top-start'],
  'left-center': ['bottom-center', 'top-center'],
  'left-end': ['bottom-end', 'top-end'],
};

// ---------------------------------------------------------------------------
// Geometry helpers
// ---------------------------------------------------------------------------

function isVirtualAnchor(
  anchor: HTMLElement | { x: number; y: number },
): anchor is { x: number; y: number } {
  return typeof (anchor as HTMLElement).getBoundingClientRect !== 'function';
}

function getAnchorRect(anchor: HTMLElement | { x: number; y: number }): Rect {
  if (isVirtualAnchor(anchor)) {
    return { x: anchor.x, y: anchor.y, width: 0, height: 0 };
  }
  const r = anchor.getBoundingClientRect();
  return { x: r.left, y: r.top, width: r.width, height: r.height };
}

function getBoundaryRect(boundary?: HTMLElement): Rect {
  if (boundary) {
    const r = boundary.getBoundingClientRect();
    return { x: r.left, y: r.top, width: r.width, height: r.height };
  }
  return { x: 0, y: 0, width: window.innerWidth, height: window.innerHeight };
}

function getBase(p: ResolvedPlacement): 'top' | 'bottom' | 'left' | 'right' {
  return p.split('-')[0] as 'top' | 'bottom' | 'left' | 'right';
}

// ---------------------------------------------------------------------------
// Position math
// ---------------------------------------------------------------------------

function rawPosition(
  a: Rect,
  fw: number,
  fh: number,
  p: ResolvedPlacement,
  gap: number,
): { x: number; y: number } {
  switch (p) {
    case 'bottom-start':
      return { x: a.x, y: a.y + a.height + gap };
    case 'bottom-center':
      return { x: a.x + a.width / 2 - fw / 2, y: a.y + a.height + gap };
    case 'bottom-end':
      return { x: a.x + a.width - fw, y: a.y + a.height + gap };
    case 'top-start':
      return { x: a.x, y: a.y - fh - gap };
    case 'top-center':
      return { x: a.x + a.width / 2 - fw / 2, y: a.y - fh - gap };
    case 'top-end':
      return { x: a.x + a.width - fw, y: a.y - fh - gap };
    case 'right-start':
      return { x: a.x + a.width + gap, y: a.y };
    case 'right-center':
      return { x: a.x + a.width + gap, y: a.y + a.height / 2 - fh / 2 };
    case 'right-end':
      return { x: a.x + a.width + gap, y: a.y + a.height - fh };
    case 'left-start':
      return { x: a.x - fw - gap, y: a.y };
    case 'left-center':
      return { x: a.x - fw - gap, y: a.y + a.height / 2 - fh / 2 };
    case 'left-end':
      return { x: a.x - fw - gap, y: a.y + a.height - fh };
  }
}

function fitsInBoundary(
  x: number,
  y: number,
  fw: number,
  fh: number,
  b: Rect,
  margin: number,
): boolean {
  return (
    x >= b.x + margin &&
    y >= b.y + margin &&
    x + fw <= b.x + b.width - margin &&
    y + fh <= b.y + b.height - margin
  );
}

function resolveWidth(
  width: 'anchor' | number | string | undefined,
  anchorWidth: number,
): string | null {
  if (width == null) return null;
  if (width === 'anchor') return `${anchorWidth}px`;
  if (typeof width === 'number') return `${width}px`;
  return width;
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Calculates the position of a floating element relative to an anchor.
 * Supports 12 named placements, auto placement, collision detection with
 * flip fallback, horizontal clamping, and max-height for vertical placements.
 *
 * Returned `x`/`y` include `window.scrollX/Y` for use with
 * `transform: translate()` on absolutely-positioned elements.
 */
export function computePosition(
  anchor: HTMLElement | { x: number; y: number },
  float: HTMLElement,
  options: PositionOptions = {},
): PositionResult {
  const {
    placement: requested = 'bottom-start',
    gap = 2,
    margin = 8,
    boundary: boundaryEl,
    width: widthOpt,
  } = options;

  const aRect = getAnchorRect(anchor);
  const fRect = float.getBoundingClientRect();
  const fw = fRect.width;
  const fh = fRect.height;
  const boundary = getBoundaryRect(boundaryEl);

  let placement: ResolvedPlacement;
  let pos: { x: number; y: number };

  if (requested === 'auto') {
    placement = AUTO_ORDER[0];
    pos = rawPosition(aRect, fw, fh, placement, gap);

    for (const candidate of AUTO_ORDER) {
      const candidatePos = rawPosition(aRect, fw, fh, candidate, gap);
      if (fitsInBoundary(candidatePos.x, candidatePos.y, fw, fh, boundary, margin)) {
        placement = candidate;
        pos = candidatePos;
        break;
      }
    }
  } else {
    placement = requested;
    pos = rawPosition(aRect, fw, fh, placement, gap);

    if (!fitsInBoundary(pos.x, pos.y, fw, fh, boundary, margin)) {
      // Try opposite side first (e.g. bottom -> top)
      const opp = OPPOSITE[placement];
      const oppPos = rawPosition(aRect, fw, fh, opp, gap);
      if (fitsInBoundary(oppPos.x, oppPos.y, fw, fh, boundary, margin)) {
        placement = opp;
        pos = oppPos;
      } else {
        // Try adjacent sides (e.g. bottom -> right, then left)
        const adj = ADJACENT[placement];
        for (const candidate of adj) {
          const adjPos = rawPosition(aRect, fw, fh, candidate, gap);
          if (fitsInBoundary(adjPos.x, adjPos.y, fw, fh, boundary, margin)) {
            placement = candidate;
            pos = adjPos;
            break;
          }
        }
      }
    }
  }

  // Horizontal clamp — prevent float from exceeding boundary edges
  pos.x = Math.max(
    boundary.x + margin,
    Math.min(pos.x, boundary.x + boundary.width - fw - margin),
  );

  // Max-height for vertical placements
  const base = getBase(placement);
  let maxHeight: number | null = null;
  if (base === 'bottom') {
    maxHeight = Math.max(50, boundary.y + boundary.height - pos.y - margin);
  } else if (base === 'top') {
    maxHeight = Math.max(50, aRect.y - boundary.y - margin);
  }

  const width = resolveWidth(widthOpt, aRect.width);

  // Convert viewport coords to document-absolute coords for transform positioning
  pos.x += window.scrollX;
  pos.y += window.scrollY;

  return { x: pos.x, y: pos.y, placement, maxHeight, width };
}
